changeSet.sql:
CREATE MATERIALIZED VIEW mv_daily_recon_summary AS WITH breaks_by_trade AS ( SELECT rb.trade_id, rb.trade_date, COUNT(*) AS total_breaks, COUNT(*) FILTER (WHERE rb.status = 'OPEN') AS open_breaks FROM recon_breaks AS rb GROUP BY rb.trade_id, rb.trade_date ) SELECT t.trade_date, c.region, i.asset_class, COUNT(*) AS total_trades, COUNT(*) FILTER (WHERE t.status = 'MATCHED') AS matched_trades, COUNT(*) FILTER ( WHERE COALESCE(b.total_breaks, 0) > 0 ) AS break_trades, COALESCE(SUM(b.open_breaks), 0)::BIGINT AS open_breaks, ROUND( COALESCE(SUM(t.quantity * t.price), 0)::NUMERIC, 2 ) AS gross_notional, ROUND( COALESCE(SUM(t.quantity * t.price), 0)::NUMERIC, 2 ) AS total_notional, ROUND( ( 100.0 * COUNT(*) FILTER (WHERE t.status = 'MATCHED') / NULLIF(COUNT(*), 0) )::NUMERIC, 2 ) AS match_rate_pct FROM trades AS t JOIN counterparties AS c ON c.id = t.counterparty_id JOIN instruments AS i ON i.id = t.instrument_id LEFT JOIN breaks_by_trade AS b ON b.trade_id = t.id AND b.trade_date = t.trade_date WHERE t.deleted_at IS NULL GROUP BY t.trade_date, c.region, i.asset_class WITH NO DATA;
REFRESH MATERIALIZED VIEW mv_daily_recon_summary;
CREATE UNIQUE INDEX uq_mv_daily_recon_summary ON mv_daily_recon_summary ( trade_date, region, asset_class );
CREATE INDEX idx_mv_daily_recon_summary_trade_date ON mv_daily_recon_summary (trade_date);
CREATE INDEX idx_mv_daily_recon_summary_region ON mv_daily_recon_summary (region);
